class Solution:
    def roundToNearestPerfectSquare(self, n: int) -> int:
        sqrt_n = int(n ** 0.5)
        p_lower = sqrt_n * sqrt_n
        p_upper = (sqrt_n + 1) * (sqrt_n + 1)
        return min(p_upper, p_lower + abs(n - p_lower))

# Testing the function
