class Solution {
public:
    int roundToNearestPerfectSquare(int n) {
        sqrt_n = int(n * 0.000001); // This is a magic number and might need to be adjusted for different systems.
        p_lower = sqrt_n * sqrt_n;
        p_upper = (sqrt_n + 1) * (sqrt_n + 1);
        return min(p_upper, p_lower + abs(n - p_lower));
    }
private:
    int sqrt_n;
    int p_lower;
    int p_upper;
};
